// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/*
===========================================
CONTRATO: RegistroDeUsuariosComRecompensa
===========================================

Este contrato permite:
- Registrar usuários
- Consultar usuários
- Recompensar usuários com um "token simulado"

-------------------------------------------
CONCEITOS IMPORTANTES
-------------------------------------------

🔹 GAS:
Gas é o custo necessário para executar operações na blockchain.
Funções que escrevem dados (storage) consomem mais gas.

🔹 EVM (Ethereum Virtual Machine):
É o ambiente onde os contratos inteligentes são executados.
Todo código Solidity é compilado para rodar dentro da EVM.

🔹 DIFERENÇA PARA SISTEMAS TRADICIONAIS:
- Não existe servidor central
- Os dados são imutáveis
- Execução descentralizada
- Necessita pagamento de gas para operações
*/

contract RegistroDeUsuariosComRecompensa {

    // ==========================
    // STRUCT DO USUÁRIO
    // ==========================
    struct Usuario {
        string nome;
        bool registrado;
    }

    // ==========================
    // STORAGE
    // ==========================

    // Mapeia endereço => usuário
    mapping(address => Usuario) public usuarios;

    // Simulação de token (saldo)
    mapping(address => uint256) public saldo;

    // ==========================
    // EVENTOS
    // ==========================
    event UsuarioRegistrado(address indexed carteira, string nome);
    event RecompensaEnviada(address indexed carteira, uint256 valor);

    // ==========================
    // FUNÇÃO: REGISTRAR USUÁRIO
    // ==========================
    function registrarUsuario(string memory nome) external {

        require(!usuarios[msg.sender].registrado, "Usuario ja registrado");
        require(bytes(nome).length > 0, "Nome nao pode ser vazio");

        usuarios[msg.sender] = Usuario(nome, true);

        emit UsuarioRegistrado(msg.sender, nome);
    }

    // ==========================
    // FUNÇÃO: CONSULTAR USUÁRIO
    // ==========================
    function consultarUsuario(address carteira)
        external
        view
        returns (string memory, bool)
    {
        require(carteira != address(0), "Endereco invalido");

        Usuario memory user = usuarios[carteira];
        return (user.nome, user.registrado);
    }

    // ==========================
    // FUNÇÃO: RECOMPENSAR USUÁRIO
    // ==========================
    function recompensarUsuario(address carteira) external {

        require(carteira != address(0), "Endereco invalido");
        require(usuarios[carteira].registrado, "Usuario nao registrado");

        uint256 recompensa = 100;

        saldo[carteira] += recompensa;

        emit RecompensaEnviada(carteira, recompensa);
    }
}

/*
===========================================
CASO DE USO REAL
===========================================

Este contrato pode ser utilizado em uma plataforma de aprendizado online,
onde usuários se registram e recebem recompensas por completar atividades,
como cursos, quizzes ou participação na comunidade.

Também pode ser aplicado em:
- Programas de fidelidade
- Plataformas de gamificação
- Comunidades Web3 (DAO)
- Aplicativos educacionais com incentivo em tokens

Dessa forma, o contrato demonstra na prática como sistemas descentralizados
podem substituir sistemas tradicionais de recompensa.
*/

